#include<bits/stdc++.h>
using namespace std;
const int N = 2e5+5 , K = (1<<20)+5 ;
int n,a[N],nxt[N][30],f[K],ans;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];//输入
    for(int i=n;i>=1;i--){//预处理
        for(int j=1;j<=20;j++)
            nxt[i][j]=nxt[i+1][j];//将上一次的复制到当前来
        nxt[i][a[i]]=i;//更新目前的
    }
    memset(f,0x3f,sizeof(f));f[0]=0;//初始化
    for(int s=0;s<(1<<20);s++){//枚举选择的状态
        if(f[s]==0x3f3f3f3f)continue;
        //如果这个状态不存在就跳过
        int cnt=0;//计算本次状态中包含的数字个数
        for(int i=1;i<=20;i++){//枚举所有数字
            if((1<<(i-1))&s)cnt++;//如果被包含了那么统计进去
            else{//否则作为下一个包含的数字来考虑
                int j=nxt[f[s]+1][i];//接下来的第一个
                int k=nxt[j+1][i];//接下来的第二个
                if(!j||!k)continue;//不存在两个相同的这个数字了
                f[s|(1<<(i-1))]=min(f[s|(1<<(i-1))],k);//更新下一个状态
            }
        }
        ans=max(ans,cnt);//将所有可能的状态包含的数字个数取个最大值
    }
    cout<<ans*2;//由于我们算的是数字个数然而题目要的是长度因此要翻倍
    return 0;
}
